class MyController(http.Controller):

    @http.route('/my_module/api/data', type='json', auth='user', methods=['POST'])
    def api_data(self, **post):
        records = request.env['my.model'].search([('active', '=', True)])
        return {'count': len(records), 'records': records.read(['name'])}

    @http.route('/my_module/page', type='http', auth='public', website=True)
    def page(self, **kwargs):
        return request.render('my_module.my_template', {'records': request.env['my.model'].search([])})
